mapper.select:
SELECT p.project_id AS projectId, p.project_name AS projectName, p.category_id AS categoryId, c.category_name AS categoryName, p.area, p.project_intro AS projectIntro, p.status, p.create_time AS createTime, COUNT(i.inheritor_id) AS inheritorCount FROM heritage_project p LEFT JOIN heritage_category c ON p.category_id = c.category_id LEFT JOIN heritage_inheritor i ON p.project_id = i.project_id AND i.status = 1
AND p.status = 1
AND p.category_id = #{query.categoryId}
AND p.area LIKE CONCAT('%', #{query.area}, '%')
AND p.project_name LIKE CONCAT('%', #{query.keyword}, '%')
GROUP BY p.project_id, p.project_name, p.category_id, c.category_name, p.area, p.project_intro, p.status, p.create_time ORDER BY p.project_id ASC LIMIT #{query.size} OFFSET #{query.offset}
